import React, { useState,useRef } from 'react';

const Journal = () => {
  const [title, setTitle] = useState('');
  const [date, setDate] = useState('');
  const [entry, setEntry] = useState('');
const textareaRef = useRef();

function autoResizeTextarea() {
  const textarea = textareaRef.current;
  if (textarea) {
    textarea.style.height = 'auto'; // reset height
    textarea.style.height = textarea.scrollHeight + 'px'; // set new height
  }
}

  function handleAnalyze() {
    // placeholder for analyze functionality
    console.log({ title, date, entry });
  }

  return (
    <>
      <div className="journal-page">
        <h1 className="journal-heading">Journal Page</h1>
        <div className="journal-header">
          <input
            className="journal-title"
            placeholder="Title (optional)"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />
          <input
            className="journal-date"
            placeholder="dd/mm/yyyy"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
        </div>

        <div className="journal-body">
          <textarea
           ref={textareaRef}
            className="journal-entry"
            placeholder="Write your journal entry here..."
            value={entry}
  //                      onChange={(e) => {
  //   setEntry(e.target.value);
  //   autoResizeTextarea();
  // }}
            onChange={(e) => setEntry(e.target.value)}
          />
        </div>

        <div className="journal-footer">
          <button className="journal-analyze" onClick={handleAnalyze}>
            Analyze
          </button>
        </div>

        <Stylesheet />
      </div>
    </>
  );
};

const Stylesheet = () => {
  return (
    <style>{`
      .journal-page {
        padding: 1rem;
        font-family: 'Cedarville Cursive', cursive;
        color: var(--text);
        display: flex;
    justify-content: center;
    flex-direction: column;
    align-items: center;
      }

      .journal-heading {
        font-size: 2.5rem;
        text-align: center;
      }

      .journal-header {
        display: flex;
        justify-content: center;
        align-items: center;
        gap: 1rem;
        width:80%;
        margin-bottom: 1rem;
      }

      .journal-title,
      .journal-date {
        background-color: var(--secondary-color);
        border: none;
        padding: 10px;
        border-radius: 5px;
        font-size: 1.2rem;
        color: var(--text);
        font-family: 'Cedarville Cursive', cursive;
      }

      .journal-title {
        flex: 2;
      }

      .journal-date {
        flex: 1;
      }

      .journal-body {
        margin-top: 1rem;
        margin-bottom: 2rem;
        width: 100%;
      }

      .journal-entry {
  margin-right:5px;
        width: 80%;
        min-height: 300px;
        background-color: var(--secondary-color);
        border: none;
        padding: 15px;
        border-radius: 5px;
        font-size: 1.2rem;
        font-family: 'Cedarville Cursive', cursive;
        color: var(--text);
        resize: vertical;
        outline: none;
        box-sizing: border-box;
      }

      .journal-footer {
        display: flex;
        justify-content: center;
      }

      .journal-analyze {
        background-color: var(--button-color);
        border: none;
        padding: 10px 20px;
        border-radius: 5px;
        font-size: 1.5rem;
        color: var(--bg-parchment);
        font-family: 'Cedarville Cursive', cursive;
        cursor: pointer;
      }
        .journal-entry::-webkit-scrollbar {
  width: 12px;
}

.journal-entry::-webkit-scrollbar-track {
  background: var(--text);
}

.journal-entry::-webkit-scrollbar-thumb {
  background-color: var(--secondary-color);
  border-radius: 10px;
  width: 8px;
}
    `}</style>
  );
};

export default Journal;
